import{_ as e,c as s,o as a,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"工具集: 记忆管理 | opencode-supermemory","description":"学习 supermemory 工具的 5 种核心模式（add, search, profile, list, forget）。通过自然语言指令控制 Agent 的记忆行为，提升开发效率。","frontmatter":{"title":"工具集: 记忆管理 | opencode-supermemory","sidebarTitle":"教 Agent 记住你的偏好","subtitle":"工具集: 记忆管理","description":"学习 supermemory 工具的 5 种核心模式（add, search, profile, list, forget）。通过自然语言指令控制 Agent 的记忆行为，提升开发效率。","tags":["工具使用","记忆管理","核心功能"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"zh/supermemoryai/opencode-supermemory/core/tools/index.md","filePath":"zh/supermemoryai/opencode-supermemory/core/tools/index.md"}'),o={name:"zh/supermemoryai/opencode-supermemory/core/tools/index.md"};function n(r,t,p,l,d,h){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="工具集详解-教-agent-记忆" tabindex="-1">工具集详解：教 Agent 记忆 <a class="header-anchor" href="#工具集详解-教-agent-记忆" aria-label="Permalink to &quot;工具集详解：教 Agent 记忆&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><p>在这一课，你将掌握 <code>supermemory</code> 插件的核心交互方式。虽然 Agent 通常会自动管理记忆，但作为开发者，你经常需要手动干预。</p><p>学完本课，你将能够：</p><ol><li>使用 <code>add</code> 模式手动保存关键技术决策。</li><li>使用 <code>search</code> 模式验证 Agent 是否记住了你的偏好。</li><li>使用 <code>profile</code> 查看 Agent 眼中的&quot;你&quot;。</li><li>使用 <code>list</code> 和 <code>forget</code> 清理过时或错误的记忆。</li></ol><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p>opencode-supermemory 并不是一个黑盒，它通过标准的 OpenCode Tool 协议与 Agent 交互。这意味着你可以像调用函数一样调用它，也可以用自然语言指挥 Agent 使用它。</p><p>插件向 Agent 注册了一个名为 <code>supermemory</code> 的工具，它就像一把瑞士军刀，拥有 6 种模式：</p><table tabindex="0"><thead><tr><th>模式</th><th>作用</th><th>典型场景</th></tr></thead><tbody><tr><td><strong>add</strong></td><td>添加记忆</td><td>&quot;记住，这个项目必须用 Bun 运行&quot;</td></tr><tr><td><strong>search</strong></td><td>搜索记忆</td><td>&quot;我之前有没有说过怎么处理鉴权？&quot;</td></tr><tr><td><strong>profile</strong></td><td>用户画像</td><td>查看 Agent 总结的你的编码习惯</td></tr><tr><td><strong>list</strong></td><td>列出记忆</td><td>审计最近保存的 10 条记忆</td></tr><tr><td><strong>forget</strong></td><td>删除记忆</td><td>删除一条错误的配置记录</td></tr><tr><td><strong>help</strong></td><td>使用指南</td><td>查看工具帮助文档</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">自动触发机制</p><p>除了手动调用，插件还会监听你的聊天内容。当你通过自然语言说出 &quot;Remember this&quot; 或 &quot;Save this&quot; 时，插件会自动检测关键词，并强制 Agent 调用 <code>add</code> 工具。</p></div><h2 id="跟我做-手动管理记忆" tabindex="-1">跟我做：手动管理记忆 <a class="header-anchor" href="#跟我做-手动管理记忆" aria-label="Permalink to &quot;跟我做：手动管理记忆&quot;">​</a></h2><p>虽然我们通常让 Agent 自动操作，但在调试或建立初始记忆时，手动调用工具非常有用。你可以在 OpenCode 的对话框中直接通过自然语言让 Agent 执行这些操作。</p><h3 id="_1-添加记忆-add" tabindex="-1">1. 添加记忆 (Add) <a class="header-anchor" href="#_1-添加记忆-add" aria-label="Permalink to &quot;1. 添加记忆 (Add)&quot;">​</a></h3><p>这是最常用的功能。你可以指定记忆的内容、类型和作用域。</p><p><strong>操作</strong>：告诉 Agent 保存一条关于项目架构的记忆。</p><p><strong>输入指令</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用 supermemory 工具保存一条记忆：</span></span>
<span class="line"><span>内容：&quot;本项目的所有服务层代码都必须放在 src/services 目录下&quot;</span></span>
<span class="line"><span>类型：architecture</span></span>
<span class="line"><span>范围：project</span></span></code></pre></div><p><strong>Agent 的内部行为</strong>（源码逻辑）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;add&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;本项目的所有服务层代码都必须放在 src/services 目录下&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;architecture&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你应该看到</strong>： Agent 返回类似这样的确认信息：</p><blockquote><p>✅ Memory added to project scope (ID: mem_12345...)</p></blockquote><div class="tip custom-block"><p class="custom-block-title">记忆类型 (Type) 的选择</p><p>为了让检索更精准，建议使用准确的类型：</p><ul><li><code>project-config</code>: 技术栈、工具链配置</li><li><code>architecture</code>: 架构模式、目录结构</li><li><code>preference</code>: 你的个人编码喜好（如&quot;喜欢箭头函数&quot;）</li><li><code>error-solution</code>: 某个报错的特定解决方案</li><li><code>learned-pattern</code>: Agent 观察到的代码模式</li></ul></div><h3 id="_2-搜索记忆-search" tabindex="-1">2. 搜索记忆 (Search) <a class="header-anchor" href="#_2-搜索记忆-search" aria-label="Permalink to &quot;2. 搜索记忆 (Search)&quot;">​</a></h3><p>当你想确认 Agent 是否&quot;知道&quot;某件事时，可以使用搜索功能。</p><p><strong>操作</strong>：搜索关于&quot;服务层&quot;的记忆。</p><p><strong>输入指令</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>查询 supermemory，关键词是&quot;services&quot;，范围是 project</span></span></code></pre></div><p><strong>Agent 的内部行为</strong>：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tool&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;supermemory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mode&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;search&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;query&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;services&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;scope&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;project&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你应该看到</strong>： Agent 列出相关的记忆片段及其相似度（Similarity）。</p><h3 id="_3-查看用户画像-profile" tabindex="-1">3. 查看用户画像 (Profile) <a class="header-anchor" href="#_3-查看用户画像-profile" aria-label="Permalink to &quot;3. 查看用户画像 (Profile)&quot;">​</a></h3><p>Supermemory 会自动维护一个&quot;用户画像&quot;，包含你的长期偏好。</p><p><strong>操作</strong>：查看你的画像。</p><p><strong>输入指令</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>调用 supermemory 工具的 profile 模式，看看你对我有什么了解</span></span></code></pre></div><p><strong>你应该看到</strong>： 返回两类信息：</p><ul><li><strong>Static</strong>: 静态事实（如&quot;用户是全栈工程师&quot;）</li><li><strong>Dynamic</strong>: 动态偏好（如&quot;用户最近在关注 Rust&quot;）</li></ul><h3 id="_4-审计与遗忘-list-forget" tabindex="-1">4. 审计与遗忘 (List &amp; Forget) <a class="header-anchor" href="#_4-审计与遗忘-list-forget" aria-label="Permalink to &quot;4. 审计与遗忘 (List &amp; Forget)&quot;">​</a></h3><p>如果 Agent 记住了错误的信息（比如一个已经废弃的 API Key），你需要删除它。</p><p><strong>第一步：列出最近记忆</strong></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>列出最近的 5 条项目记忆</span></span></code></pre></div><p><em>(Agent 调用 <code>mode: &quot;list&quot;, limit: 5</code>)</em></p><p><strong>第二步：获取 ID 并删除</strong> 假设你看到一条错误的记忆 ID 为 <code>mem_abc123</code>。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>删除记忆 ID 为 mem_abc123 的记录</span></span></code></pre></div><p><em>(Agent 调用 <code>mode: &quot;forget&quot;, memoryId: &quot;mem_abc123&quot;</code>)</em></p><p><strong>你应该看到</strong>：</p><blockquote><p>✅ Memory mem_abc123 removed from project scope</p></blockquote><h2 id="进阶-自然语言触发" tabindex="-1">进阶：自然语言触发 <a class="header-anchor" href="#进阶-自然语言触发" aria-label="Permalink to &quot;进阶：自然语言触发&quot;">​</a></h2><p>你不需要每次都详细描述工具参数。插件内置了关键词检测机制。</p><p><strong>试一试</strong>： 在对话中直接说：</p><blockquote><p><strong>Remember this</strong>: 所有的日期处理都必须使用 date-fns 库，禁止使用 moment.js。</p></blockquote><p><strong>发生了什么？</strong></p><ol><li>插件的 <code>chat.message</code> 钩子检测到关键词 &quot;Remember this&quot;。</li><li>插件向 Agent 注入了一个系统提示：<code>[MEMORY TRIGGER DETECTED]</code>。</li><li>Agent 收到指令：&quot;You MUST use the supermemory tool with mode: &#39;add&#39;...&quot;。</li><li>Agent 自动提取内容并调用工具。</li></ol><p>这是一个非常自然的交互方式，让你在编码过程中随时&quot;固化&quot;知识。</p><h2 id="常见问题-faq" tabindex="-1">常见问题 (FAQ) <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 (FAQ)&quot;">​</a></h2><p><strong>Q: <code>scope</code> 默认是什么？</strong> A: 默认为 <code>project</code>。如果你想保存跨项目通用的偏好（比如&quot;我总是使用 TypeScript&quot;），请显式指定 <code>scope: &quot;user&quot;</code>。</p><p><strong>Q: 为什么我添加的记忆没有立即生效？</strong> A: <code>add</code> 操作是异步的。通常 Agent 会在工具调用成功后立即&quot;知道&quot;这条新记忆，但在某些极端网络延迟下可能需要几秒钟。</p><p><strong>Q: 敏感信息会被上传吗？</strong> A: 插件会自动脱敏 <code>&lt;private&gt;</code> 标签内的内容。但为了安全，建议不要将密码或 API Key 放入记忆中。</p><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>工具定义</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr><tr><td>关键词检测</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L34-L37" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>34-37</td></tr><tr><td>触发提示词</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L20-L28" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>20-28</td></tr><tr><td>客户端实现</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/client.ts" target="_blank" rel="noreferrer"><code>src/services/client.ts</code></a></td><td>全文</td></tr></tbody></table><p><strong>关键类型定义</strong>：</p><ul><li><code>MemoryType</code>: 定义在 <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li><li><code>MemoryScope</code>: 定义在 <a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/types/index.ts" target="_blank" rel="noreferrer"><code>src/types/index.ts</code></a></li></ul></details><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../memory-management/">记忆作用域与生命周期</a></strong>。</p><p>你会学到：</p><ul><li>User Scope 和 Project Scope 的底层隔离机制</li><li>如何设计高效的记忆分区策略</li><li>记忆的生命周期管理</li></ul></blockquote>`,63)])])}const g=e(o,[["render",n]]);export{u as __pageData,g as default};
